            </button>
            <button
              onClick={() => {
                const title = idea.split("\n")[0]?.trim() || "Untitled Ticket";
                setManualTitle(title);
                setManualMarkdown(emptyTicketMarkdown(title));
                setDraftMessage("Manual ticket template ready. You can save without waiting for Codex.");
