:root {
  color-scheme: dark;
  --relay-font-sans:
    Inter, "DM Sans", ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --relay-font-mono: "SF Mono", "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
  --relay-bg: #0a0a09;
  --relay-chrome: #0d0d0c;
  --relay-sidebar: #11110f;
  --relay-surface: #151512;
  --relay-surface-2: #191916;
  --relay-surface-3: #20201c;
  --relay-surface-hover: #23231f;
  --relay-surface-active: #2a2925;
  --relay-popover: #181815;
  --relay-input: #121210;
  --relay-text: #f0eee7;
  --relay-text-muted: #aaa49a;
  --relay-text-subtle: #7f786e;
  --relay-text-inverse: #07100d;
  --relay-border-soft: rgb(255 255 255 / 5%);
  --relay-border: rgb(255 255 255 / 8%);
  --relay-border-strong: rgb(255 255 255 / 14%);
  --relay-primary: #8bd7c3;
  --relay-primary-hover: #9de2d0;
  --relay-primary-muted: rgb(139 215 195 / 13%);
  --relay-ring: rgb(139 215 195 / 64%);
  --relay-info: #8fb8ff;
  --relay-info-muted: rgb(143 184 255 / 14%);
  --relay-success: #87d38b;
  --relay-success-muted: rgb(135 211 139 / 13%);
  --relay-warning: #e7c36a;
  --relay-warning-muted: rgb(231 195 106 / 14%);
  --relay-danger: #ff8f80;
  --relay-danger-muted: rgb(255 143 128 / 14%);
  --relay-info-text: #b5ccff;
  --relay-success-text: #a7dfa9;
  --relay-warning-text: #f3d78c;
  --relay-danger-text: #ffb1a7;
  --relay-radius-xs: 4px;
  --relay-radius-sm: 6px;
  --relay-radius-md: 8px;
  --relay-radius-lg: 10px;
  --relay-space-1: 4px;
  --relay-space-2: 8px;
  --relay-space-3: 12px;
  --relay-space-4: 16px;
  --relay-space-5: 20px;
  --relay-space-6: 24px;
  --relay-text-xs: 11px;
  --relay-text-sm: 12px;
  --relay-text-md: 13px;
  --relay-text-base: 14px;
  --relay-text-lg: 16px;
  --relay-text-xl: 20px;
  --relay-shadow-sm: 0 1px 2px rgb(0 0 0 / 24%);
  --relay-shadow-panel: 0 16px 48px rgb(0 0 0 / 26%);
  --relay-shadow-modal: 0 28px 90px rgb(0 0 0 / 46%);
  --relay-inset-highlight: inset 0 1px 0 rgb(255 255 255 / 5%);
  --relay-focus-ring: 0 0 0 2px var(--relay-bg), 0 0 0 4px var(--relay-ring);
  font-family: var(--relay-font-sans);
  background: var(--relay-bg);
  color: var(--relay-text);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  background: linear-gradient(180deg, var(--relay-chrome) 0%, var(--relay-bg) 46%);
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  min-height: 32px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  color: var(--relay-text);
  padding: 0 11px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--relay-space-2);
  cursor: pointer;
  box-shadow: var(--relay-inset-highlight);
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    box-shadow 140ms ease,
    transform 90ms ease;
}

button:hover {
  border-color: var(--relay-border-strong);
  background: var(--relay-surface-hover);
}

button:active {
  transform: translateY(1px);
  background: var(--relay-surface-active);
  box-shadow: none;
}

button:focus-visible,
input:focus-visible,
textarea:focus-visible,
select:focus-visible {
  outline: none;
  box-shadow: var(--relay-focus-ring);
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.52;
  transform: none;
}

button svg {
  flex: 0 0 auto;
.topbar h1,
.topbar p {
  margin: 0;
}

.brand h1 {
  font-size: var(--relay-text-lg);
  line-height: 1.1;
  letter-spacing: 0;
}

.brand p {
  margin-top: 2px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.primary-button {
  border-color: color-mix(in srgb, var(--relay-primary) 70%, transparent);
  background: var(--relay-primary);
  color: var(--relay-text-inverse);
  font-weight: 680;
  box-shadow:
    inset 0 1px 0 rgb(255 255 255 / 28%),
    0 8px 22px rgb(139 215 195 / 13%);
}

.primary-button:hover {
  border-color: var(--relay-primary-hover);
  background: var(--relay-primary-hover);
}

.primary-button:disabled {
  background: var(--relay-surface-3);
  border-color: var(--relay-border);
  color: var(--relay-text-muted);
  box-shadow: none;
}

.full {
  width: 100%;
}

.sidebar-list {
  display: flex;
  flex-direction: column;
  gap: var(--relay-space-1);
  min-height: 0;
  overflow-y: auto;
  padding-right: 2px;
}

.project-row {
  width: 100%;
  min-height: 48px;
  justify-content: space-between;
  text-align: left;
  padding: 8px;
  border-color: transparent;
  background: transparent;
  box-shadow: none;
}

.project-row:hover {
  border-color: var(--relay-border-soft);
  background: var(--relay-surface-hover);
}

.project-row.selected {
  border-color: color-mix(in srgb, var(--relay-primary) 32%, transparent);
  background: var(--relay-primary-muted);
  color: var(--relay-text);
}

.project-main {
  min-width: 0;
  display: grid;
  gap: 3px;
}

.project-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-weight: 690;
}

.project-path {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  background: var(--relay-input);
  color: var(--relay-text-subtle);
  padding: 0 10px;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  box-shadow: var(--relay-inset-highlight);
  transition:
    border-color 140ms ease,
    box-shadow 140ms ease;
}

.search:focus-within {
  border-color: color-mix(in srgb, var(--relay-primary) 62%, transparent);
  box-shadow: var(--relay-focus-ring);
}

.search input {
  min-height: 0;
  border: 0;
  border-radius: 0;
  background: transparent;
  padding: 0;
  box-shadow: none;
}

.search input:focus-visible {
  box-shadow: none;
}

.health {
  border: 1px solid color-mix(in srgb, var(--relay-warning) 44%, transparent);
  border-radius: var(--relay-radius-md);
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
  padding: 9px 11px;
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: var(--relay-space-2);
}

.health.error {
  border-color: color-mix(in srgb, var(--relay-danger) 42%, transparent);
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.board {
  display: grid;
  grid-auto-columns: minmax(270px, 310px);
  grid-auto-flow: column;
  gap: 10px;
  min-height: 0;
  overflow: auto;
  padding-bottom: var(--relay-space-2);
}

.board-column {
  min-height: 0;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface);
  display: flex;
  flex-direction: column;
  box-shadow: var(--relay-inset-highlight);
}

.board-column.over {
  border-color: color-mix(in srgb, var(--relay-primary) 62%, transparent);
  box-shadow:
    inset 0 0 0 1px color-mix(in srgb, var(--relay-primary) 32%, transparent),
    var(--relay-inset-highlight);
}

.column-header {
  min-height: 38px;
  border-bottom: 1px solid var(--relay-border);
  padding: 0 10px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.column-header h2 {

.codex-status {
  pointer-events: all;
  width: 292px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: color-mix(in srgb, var(--relay-popover) 88%, transparent);
  color: var(--relay-text);
  padding: 9px;
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 10px;
  box-shadow: var(--relay-shadow-panel);
  backdrop-filter: blur(14px);
}

.codex-status.ok svg {
  color: var(--relay-primary);
}

.codex-status strong,
.codex-status span {
  display: block;
}

.codex-status strong {
  font-size: var(--relay-text-md);
}

.codex-status span {

.markdown-content ul,
.markdown-content ol {
  padding-left: 22px;
}

.markdown-content li + li {
  margin-top: 4px;
}

.markdown-content blockquote {
  border-left: 3px solid var(--relay-border-strong);
  color: var(--relay-text-muted);
  padding: 2px 0 2px 11px;
}

.markdown-content a {
  color: var(--relay-primary);
  text-decoration: none;
}

.markdown-content a:hover {
  text-decoration: underline;
}

.markdown-link-unsafe {
  color: var(--relay-text-muted);
}

.markdown-content :not(pre) > code {
  border: 1px solid var(--relay-border-soft);
}

.clarification-question {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: var(--relay-space-2);
  align-items: flex-start;
}

.clarification-question svg {
  margin-top: 2px;
  color: var(--relay-primary);
}

.clarification-question .markdown-block,
.clarification-answer .markdown-block {
  min-width: 0;
}

.clarification-question p,
.clarification-answer p {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  align-items: center;
  gap: 10px;
}

.agent-progress-icon {
  width: 30px;
  height: 30px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  color: var(--relay-primary);
  display: grid;
  place-items: center;
}

.agent-progress-main strong,
.agent-progress-main span {
  display: block;
}

